    // then $u_i$ can become $m_j$.

    // Let's use $m_i$ to store the minimum possible value for an initial element $u_i$.

    const uniqueNums = Array.from(new Set(nums)).sort((a, b) => a - b);
    const U = uniqueNums.length;
    const minimalValues = new Map(); // Map from initial value $u_i$ to its minimal achievable value $m_i$.

    for (let i = 0; i < U; i++) {
        const ui = uniqueNums[i];
        let minVal = ui;

