            if (ui % uj === 0) {
                const reduced_uj = minimalValues.get(uj);
                minVal = Math.min(minVal, reduced_uj);
            }
        }
        minimalValues.set(ui, minVal);
    }

    // Now calculate the total sum
    let totalSum = 0;
    for (const num of nums) {
        // The original num must exist in uniqueNums, so it has a calculated minimal value.
        totalSum += minimalValues.get(num);
    }

    return totalSum;
